/**
 * Configuration node: Define assets to track.
 * This node maps human-readable names to CoinGecko API IDs (slugs).
 */

// List of assets to be fetched from the API
const coinIds = {
  Bitcoin: "bitcoin",
  Ethereum: "ethereum",
  BNB: "binancecoin",
  Solana: "solana",
  Hyperliquid: "hyperliquid",
  Cardano: "cardano",
  Chainlink: "chainlink",
  TON: "the-open-network",
  Avalanche: "avalanche-2",
  Sui: "sui",
  Polkadot: "polkadot",
  Uniswap: "uniswap"
};

// Extract API slugs from the configuration object and join them into a comma-separated string for the API request.
return {
  ids: Object.values(coinIds).join(',')
};

/**
 * Processes cryptocurrency market data and generates 
 * a formatted HTML message for Telegram.
 */

// Extract the raw data array from the preceding Aggregate node
const coins = $input.first().json.data;

// Initialize message with a concise header
let message = "<b>📈 Current Crypto Prices</b>\n\n";

/**
 * Iterate through the dataset to build the report lines.
 * Prices and 24h percentage changes are formatted for readability.
 */
for (const coin of coins) {
  const currentPrice = coin.current_price;
  const changePercentage = coin.price_change_percentage_24h || 0;

  // Set directional indicator based on the price movement
  const trendIndicator = changePercentage >= 0 ? "🔼" : "🔻";

  // Dynamic price formatting: 
  // Use 4 decimal places for low-value assets and 2 for major assets
  const formattedPrice = currentPrice < 1 
    ? currentPrice.toFixed(4) 
    : currentPrice.toLocaleString('en-US', { 
        minimumFractionDigits: 2, 
        maximumFractionDigits: 2 
      });

  const formattedChange = changePercentage.toFixed(2);

  // Build the message line using HTML tags for Telegram ParseMode compatibility
  message += `${coin.name}: <i>$${formattedPrice} (${formattedChange}%)</i> ${trendIndicator}\n`;
}

return { message };
